import os
from cryptography.fernet import Fernet
from cryptography.hazmat.backends import default_backend
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
import base64

# Load encryption key from application config
def load_key():
    return os.environ.get("ENCRYPTION_KEY").encode()

# Generate a key from a password
def generate_key(password: str):
    salt = os.urandom(16)
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=100000,
        backend=default_backend()
    )
    key = base64.urlsafe_b64encode(kdf.derive(password.encode()))
    return key, salt

# Encrypt credit card number
def encrypt_credit_card(card_number: str, key: bytes) -> str:
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(card_number.encode())
    return encrypted_card.decode()

# Decrypt credit card number
def decrypt_credit_card(encrypted_card: str, key: bytes) -> str:
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card.encode())
    return decrypted_card.decode()

# Example usage
def main():
    password = "your_secure_password"  # Use a secure password
    key, salt = generate_key(password)
    encrypted_card = encrypt_credit_card("4111111111111111", key)
    print("Encrypted:", encrypted_card)
    decrypted_card = decrypt_credit_card(encrypted_card, key)
    print("Decrypted:", decrypted_card)

if __name__ == "__main__":
    main()